    input wire clk,

    input wire pulse_i,
    output wire pulse_o);reg [1:0] pulse_hist_ff;
  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
    pulse_hist_ff <= {pulse_hist_ff[0], pulse_i};
